package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

/**
 * Generates exhaustive and random test cases from a list of argument nodes.
 */
public class BaseSetGenerator {
    private final List<APyNode<?>> argNodes;
    private int numRand;
    private Set<TestCase> currentTests;

    public BaseSetGenerator(List<APyNode<?>> argNodes, int numRand) {
        this.argNodes = argNodes;
        this.numRand = numRand;
        this.currentTests = new HashSet<>();
    }

    public Set<TestCase> genExTests() {
        Set<TestCase> retval = new HashSet<>();
        buildExTests(0, new ArrayList<>(), retval);
        this.currentTests = new HashSet<>(retval);
        return retval;
    }

    public Set<TestCase> genRandTests() {
        Set<TestCase> retval = new HashSet<>();
        if (this.numRand <= 0) {
            return retval;
        }

        int attempts = 0;
        int maxAttempts = Math.max(1000, this.numRand * 200);
        while (retval.size() < this.numRand && attempts < maxAttempts) {
            TestCase candidate = genOneRandTest();
            if (!this.currentTests.contains(candidate)) {
                retval.add(candidate);
            }
            attempts++;
        }
        this.currentTests.addAll(retval);
        return retval;
    }

    public Set<TestCase> genRandTests(int numTests) {
        this.numRand = numTests;
        return this.genRandTests();
    }

    public List<TestCase> genBaseSet() {
        Set<TestCase> exTests = this.genExTests();
        Set<TestCase> randTests = this.genRandTests();

        List<TestCase> retval = new ArrayList<>(exTests);
        retval.addAll(randTests);
        return retval;
    }

    public List<TestCase> genTests(int numRand) {
        this.numRand = numRand;
        return this.genBaseSet();
    }

    private void buildExTests(int idx, List<APyObj> currentArgs, Set<TestCase> out) {
        if (idx == this.argNodes.size()) {
            out.add(new TestCase(currentArgs));
            return;
        }

        APyNode<?> node = this.argNodes.get(idx);
        for (Object obj : node.genExVals()) {
            currentArgs.add((APyObj) obj);
            buildExTests(idx + 1, currentArgs, out);
            currentArgs.remove(currentArgs.size() - 1);
        }
    }

    private TestCase genOneRandTest() {
        List<APyObj> args = new ArrayList<>();
        for (APyNode<?> node : this.argNodes) {
            args.add((APyObj) node.genRandVal());
        }
        return new TestCase(args);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;

import java.util.ArrayList;
import java.util.List;

/**
 * Shared behavior for iterable nodes.
 *
 * @param <ObjType> generated iterable object type
 */
public abstract class AIterablePyNode<ObjType extends APyObj> extends APyNode<ObjType> {
    protected List<Integer> exDomain;
    protected List<Integer> ranDomain;
    protected APyNode<?> leftChild;
    protected APyNode<?> rightChild;

    protected AIterablePyNode(APyNode<?> leftChild, APyNode<?> rightChild) {
        this.exDomain = new ArrayList<>();
        this.ranDomain = new ArrayList<>();
        this.leftChild = leftChild;
        this.rightChild = rightChild;
    }

    @Override
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    @Override
    public void setExDomain(List<?> domain) {
        this.exDomain = castIntList(domain);
    }

    @Override
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    @Override
    public void setRanDomain(List<?> domain) {
        this.ranDomain = castIntList(domain);
    }

    @Override
    public APyNode<?> getLeftChild() {
        return this.leftChild;
    }

    @Override
    public APyNode<?> getRightChild() {
        return this.rightChild;
    }

    protected List<Integer> castIntList(List<?> domain) {
        List<Integer> retval = new ArrayList<>();
        for (Object elem : domain) {
            retval.add((Integer) elem);
        }
        return retval;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;

import java.util.List;
import java.util.Set;

/**
 * Abstract base class for all python nodes.
 *
 * @param <ObjType> generated python object type
 */
public abstract class APyNode<ObjType extends APyObj> {

    public abstract List<?> getExDomain();

    public abstract void setExDomain(List<?> domain);

    public abstract List<?> getRanDomain();

    public abstract void setRanDomain(List<?> domain);

    public abstract APyNode<?> getLeftChild();

    public abstract APyNode<?> getRightChild();

    public abstract Set<ObjType> genExVals();

    public abstract ObjType genRandVal();
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyDictObj;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.HashSet;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Random;
import java.util.Set;

/**
 * Generates Python dict values.
 *
 * @param <KeyType> key type
 * @param <ValType> value type
 */
public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
        extends AIterablePyNode<PyDictObj<KeyType, ValType>> {
    private final Random rng;

    public PyDictNode(APyNode<KeyType> keyChild, APyNode<ValType> valChild) {
        super(keyChild, valChild);
        this.rng = new Random();
    }

    @Override
    @SuppressWarnings("unchecked")
    public Set<PyDictObj<KeyType, ValType>> genExVals() {
        Set<PyDictObj<KeyType, ValType>> retval = new HashSet<>();
        List<KeyType> keys = new ArrayList<>((Set<KeyType>) this.leftChild.genExVals());
        List<ValType> vals = new ArrayList<>((Set<ValType>) this.rightChild.genExVals());

        for (Integer len : this.exDomain) {
            buildDicts(keys, vals, 0, len, new ArrayList<>(), retval);
        }
        return retval;
    }

    @Override
    @SuppressWarnings("unchecked")
    public PyDictObj<KeyType, ValType> genRandVal() {
        int len = this.ranDomain.get(this.rng.nextInt(this.ranDomain.size()));
        APyNode<KeyType> keyNode = (APyNode<KeyType>) this.leftChild;
        APyNode<ValType> valNode = (APyNode<ValType>) this.rightChild;
        Map<KeyType, ValType> retval = new LinkedHashMap<>();

        int attempts = 0;
        int maxAttempts = Math.max(200, len * 200);
        while (retval.size() < len && attempts < maxAttempts) {
            retval.put(keyNode.genRandVal(), valNode.genRandVal());
            attempts++;
        }

        return new PyDictObj<>(retval);
    }

    private void buildDicts(List<KeyType> keys, List<ValType> vals, int start, int remaining,
                            List<KeyType> chosenKeys, Set<PyDictObj<KeyType, ValType>> out) {
        if (remaining < 0) {
            return;
        }
        if (remaining == 0) {
            assignValues(chosenKeys, vals, 0, new HashMap<>(), out);
            return;
        }
        for (int idx = start; idx < keys.size(); idx++) {
            chosenKeys.add(keys.get(idx));
            buildDicts(keys, vals, idx + 1, remaining - 1, chosenKeys, out);
            chosenKeys.remove(chosenKeys.size() - 1);
        }
    }

    private void assignValues(List<KeyType> keys, List<ValType> vals, int idx,
                              Map<KeyType, ValType> cur,
                              Set<PyDictObj<KeyType, ValType>> out) {
        if (idx == keys.size()) {
            out.add(new PyDictObj<>(new HashMap<>(cur)));
            return;
        }

        KeyType key = keys.get(idx);
        for (ValType val : vals) {
            cur.put(key, val);
            assignValues(keys, vals, idx + 1, cur, out);
            cur.remove(key);
        }
    }
}

package main.rice.node;

import main.rice.obj.PyIntObj;

import java.util.ArrayList;
import java.util.List;
import java.util.Random;
import java.util.Set;
import java.util.HashSet;

/**
 * Generates Python int values.
 */
public class PyIntNode extends APyNode<PyIntObj> {
    private List<Integer> exDomain;
    private List<Integer> ranDomain;
    private final Random rng;

    public PyIntNode() {
        this.exDomain = new ArrayList<>();
        this.ranDomain = new ArrayList<>();
        this.rng = new Random();
    }

    @Override
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    @Override
    public void setExDomain(List<?> domain) {
        this.exDomain = new ArrayList<>();
        for (Object elem : domain) {
            this.exDomain.add((Integer) elem);
        }
    }

    @Override
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    @Override
    public void setRanDomain(List<?> domain) {
        this.ranDomain = new ArrayList<>();
        for (Object elem : domain) {
            this.ranDomain.add((Integer) elem);
        }
    }

    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> retval = new HashSet<>();
        for (Integer val : this.exDomain) {
            retval.add(new PyIntObj(val));
        }
        return retval;
    }

    @Override
    public PyIntObj genRandVal() {
        Integer val = this.ranDomain.get(this.rng.nextInt(this.ranDomain.size()));
        return new PyIntObj(val);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyListObj;

import java.util.ArrayList;
import java.util.List;
import java.util.Random;
import java.util.HashSet;
import java.util.Set;

/**
 * Generates Python list values.
 *
 * @param <InnerType> type of list elements
 */
public class PyListNode<InnerType extends APyObj> extends AIterablePyNode<PyListObj<InnerType>> {
    private final Random rng;

    public PyListNode(APyNode<InnerType> leftChild) {
        super(leftChild, null);
        this.rng = new Random();
    }

    @Override
    @SuppressWarnings("unchecked")
    public Set<PyListObj<InnerType>> genExVals() {
        Set<PyListObj<InnerType>> retval = new HashSet<>();
        List<InnerType> elems = new ArrayList<>((Set<InnerType>) this.leftChild.genExVals());

        for (Integer len : this.exDomain) {
            buildLists(elems, len, new ArrayList<>(), retval);
        }
        return retval;
    }

    @Override
    @SuppressWarnings("unchecked")
    public PyListObj<InnerType> genRandVal() {
        int len = this.ranDomain.get(this.rng.nextInt(this.ranDomain.size()));
        List<InnerType> retval = new ArrayList<>();

        APyNode<InnerType> child = (APyNode<InnerType>) this.leftChild;
        for (int idx = 0; idx < len; idx++) {
            retval.add(child.genRandVal());
        }

        return new PyListObj<>(retval);
    }

    private void buildLists(List<InnerType> elems, int len, List<InnerType> cur,
                            Set<PyListObj<InnerType>> out) {
        if (len < 0) {
            return;
        }
        if (cur.size() == len) {
            out.add(new PyListObj<>(new ArrayList<>(cur)));
            return;
        }
        for (InnerType elem : elems) {
            cur.add(elem);
            buildLists(elems, len, cur, out);
            cur.remove(cur.size() - 1);
        }
    }
}

