package main.rice.node;

import main.rice.obj.PyStringObj;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Random;
import java.util.Set;

/**
 * Generates Python string values.
 */
public class PyStringNode extends AIterablePyNode<PyStringObj> {
    private final String chars;
    private final Random rng;

    public PyStringNode(String chars) {
        super(null, null);
        this.chars = chars;
        this.rng = new Random();
    }

    @Override
    public Set<PyStringObj> genExVals() {
        Set<PyStringObj> retval = new HashSet<>();
        List<Character> alphabet = new ArrayList<>();
        for (int idx = 0; idx < this.chars.length(); idx++) {
            alphabet.add(this.chars.charAt(idx));
        }

        for (Integer len : this.exDomain) {
            buildStrings(alphabet, len, new StringBuilder(), retval);
        }
        return retval;
    }

    @Override
    public PyStringObj genRandVal() {
        int len = this.ranDomain.get(this.rng.nextInt(this.ranDomain.size()));
        StringBuilder sb = new StringBuilder();
        for (int idx = 0; idx < len; idx++) {
            int charIdx = this.rng.nextInt(this.chars.length());
            sb.append(this.chars.charAt(charIdx));
        }
        return new PyStringObj(sb.toString());
    }

    private void buildStrings(List<Character> alphabet, int len, StringBuilder cur,
                              Set<PyStringObj> out) {
        if (len < 0) {
            return;
        }
        if (cur.length() == len) {
            out.add(new PyStringObj(cur.toString()));
            return;
        }
        for (Character c : alphabet) {
            cur.append(c);
            buildStrings(alphabet, len, cur, out);
            cur.deleteCharAt(cur.length() - 1);
        }
    }
}

